## 4. Existing gRPC Service Implementations

**Pattern from grpc-skill/SKILL.md**:

### Server-side (call/ module):
```kotlin
@GrpcService
class CallHistoryGrpcService(
    private val callService: CallService,
) : CallServiceGrpc.CallServiceImplBase() {

    override fun getCallHistory(
        request: GetCallHistoryRequest,
        responseObserver: StreamObserver<GetCallHistoryResponse>,
    ) {
        try {
            val result = callService.getCallHistory(request.userId)
            val response = GetCallHistoryResponse.newBuilder()
                .addAllCalls(result.map { it.toProto() })
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Internal error")
                    .asRuntimeException()
            )
        }
    }
}
```

