## 6. Key gRPC Communication Pattern for Call History

### Proto Definition (protobuf/src/main/proto/call/call.proto)

```protobuf
syntax = "proto3";
package call;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.call";

service CallService {
  rpc GetCallHistory(GetCallHistoryRequest) returns (GetCallHistoryResponse);
  rpc RecordCall(RecordCallRequest) returns (RecordCallResponse);
  rpc ListCalls(ListCallsRequest) returns (ListCallsResponse);
}

message GetCallHistoryRequest {
  string user_id = 1;
}

message GetCallHistoryResponse {
  repeated CallRecord calls = 1;
}

message CallRecord {
  string id = 1;
  string caller_id = 2;
  string callee_id = 3;
  int64 start_time = 4;
  int64 end_time = 5;
  int32 duration_seconds = 6;
  string call_status = 7;
  string created_at = 8;
}

message RecordCallRequest {
  string caller_id = 1;
  string callee_id = 2;
  int64 start_time = 3;
  int64 end_time = 4;
  int32 duration_seconds = 5;
  string call_status = 6;
}

message RecordCallResponse {
  string call_id = 1;
  bool success = 2;
}

message ListCallsRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}

message ListCallsResponse {
  repeated CallRecord calls = 1;
  int32 total_count = 2;
}
```

